import { BedrockRuntimeClient, ConverseCommand } from '@aws-sdk/client-bedrock-runtime';
import type { APIGatewayProxyEventV2, APIGatewayProxyStructuredResultV2 } from 'aws-lambda';

const corsHeaders: Record<string, string> = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
};

const TITLE_MAX_LENGTH = 42;

export type HeadlineItem = { title: string; url: string };

function headlineArticleUrl(title: string): string {
    return `https://news.google.com/search?q=${encodeURIComponent(title)}&hl=en-US&gl=US&ceid=US:en`;
}

function truncateTitle(title: string): string {
    const normalized = title.replace(/\s+/g, ' ').trim();
    if (normalized.length <= TITLE_MAX_LENGTH) return normalized;
    const cut = normalized.slice(0, TITLE_MAX_LENGTH);
    const lastSpace = cut.lastIndexOf(' ');
    if (lastSpace >= Math.floor(TITLE_MAX_LENGTH * 0.55)) return cut.slice(0, lastSpace).trim();
    return cut.trim();
}

function toHeadlineItem(title: string): HeadlineItem {
    const trimmed = truncateTitle(title);
    return { title: trimmed, url: headlineArticleUrl(trimmed) };
}

/** Shown when Bedrock is unavailable or returns no parseable headlines. */
const FALLBACK_HEADLINES: HeadlineItem[] = [
    'NBA playoff seeding race tightens',
    'NFL offseason reshapes contenders',
    'MLB spring storylines take shape',
    'NHL teams push for playoff spots',
    'College hoops portal shakes up rosters',
    'Soccer leagues enter crucial stretch',
    'Tennis and golf headline busy weekend',
    'Olympic sports build global momentum',
].map(toHeadlineItem);

function parseHeadlinesFromModelText(text: string): HeadlineItem[] {
    let raw = text.trim();
    const fence = raw.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
    if (fence) raw = fence[1].trim();
    try {
        const parsed = JSON.parse(raw) as { headlines?: unknown };
        if (!Array.isArray(parsed.headlines)) return [];
        const out: HeadlineItem[] = [];
        const seen = new Set<string>();
        for (const item of parsed.headlines) {
            let title = '';
            if (typeof item === 'string') {
                title = item;
            } else if (item && typeof item === 'object' && typeof (item as { title?: unknown }).title === 'string') {
                title = (item as { title: string }).title;
            }
            if (!title) continue;
            const headline = toHeadlineItem(title);
            if (seen.has(headline.title)) continue;
            seen.add(headline.title);
            out.push(headline);
            if (out.length >= 12) break;
        }
        return out;
    } catch {
        return [];
    }
}

export const handler = async (
    event: APIGatewayProxyEventV2
): Promise<APIGatewayProxyStructuredResultV2> => {
    const method = event.requestContext?.http?.method ?? 'GET';

    if (method === 'OPTIONS') {
        return {
            statusCode: 204,
            headers: {
                ...corsHeaders,
                'Access-Control-Allow-Methods': 'GET, OPTIONS',
                'Access-Control-Allow-Headers': 'content-type, authorization',
            },
            body: '',
        };
    }

    if (method !== 'GET') {
        return {
            statusCode: 405,
            headers: corsHeaders,
            body: JSON.stringify({ headlines: [] }),
        };
    }

    try {
        const modelId =
            process.env.HEADLINES_MODEL_ID ?? 'us.anthropic.claude-haiku-4-5-20251001-v1:0';
        const region = process.env.AWS_REGION ?? 'us-east-1';
        const client = new BedrockRuntimeClient({ region });

        const system =
            'You output only valid JSON. No markdown fences. Short neutral sports-news one-liners. No URLs in text, no betting or investment advice, no profanity. If uncertain, use plausible generic sports-season storylines.';

        const user =
            `Return a single JSON object with key "headlines": an array of exactly 8 objects, each with "title" (string, max ${TITLE_MAX_LENGTH} characters, complete phrase, no truncation ellipsis). Varied topics across major sports. No duplicate themes.`;

        const response = await client.send(
            new ConverseCommand({
                modelId,
                system: [{ text: system }],
                messages: [{ role: 'user', content: [{ text: user }] }],
                inferenceConfig: { maxTokens: 900, temperature: 0.65 },
            })
        );

        const content = response.output?.message?.content;
        let text = '';
        if (content) {
            for (const block of content) {
                if ('text' in block && typeof block.text === 'string') {
                    text = block.text;
                    break;
                }
            }
        }

        const headlines = parseHeadlinesFromModelText(text);
        const resolved = headlines.length > 0 ? headlines : FALLBACK_HEADLINES;

        return {
            statusCode: 200,
            headers: corsHeaders,
            body: JSON.stringify({ headlines: resolved }),
        };
    } catch (err) {
        console.error('headlines handler error', err);
        return {
            statusCode: 200,
            headers: corsHeaders,
            body: JSON.stringify({ headlines: FALLBACK_HEADLINES }),
        };
    }
};
